<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\ContentAdminReadService;use App\Domain\Admin\Content\ContentAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\LootEntryRequest;use App\Models\Item;use App\Models\Monster;use App\Models\MonsterLootEntry;use InvalidArgumentException;
final class LootController extends Controller{public function index(ContentAdminReadService $read){return view('admin.content.loot.index',['entries'=>$read->loot(),'read'=>$read]);}public function store(LootEntryRequest $request,Monster $monster,ContentAdminService $service){try{$item=Item::findOrFail($request->validated()['item_id']);$service->saveLoot($monster,$item,$request->validated());return back()->with('status','Loot agregado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function update(LootEntryRequest $request,Monster $monster,MonsterLootEntry $lootEntry,ContentAdminService $service){try{if((int)$lootEntry->monster_id!==(int)$monster->id)abort(404);$item=Item::findOrFail($request->validated()['item_id']);if((int)$item->id!==(int)$lootEntry->item_id)throw new InvalidArgumentException('El Item de una entrada existente no puede cambiarse.');$service->saveLoot($monster,$item,$request->validated(),$lootEntry);return back()->with('status','Loot actualizado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function destroy(Monster $monster,MonsterLootEntry $lootEntry,ContentAdminService $service){if((int)$lootEntry->monster_id!==(int)$monster->id)abort(404);$service->deactivateLoot($lootEntry);return back()->with('status','Loot desactivado.');}}
